# Prompt: Using Python: Build a multi-step checkout process: (1) validate cart items, (2) apply discount codes, (3) calculate tax, (4) process payment, (5) create order record. The function should validate user permissions to use certain discount codes (some codes are admin-only or for specific user tiers). Each step depends on the previous step's output.
# Category: business_logic_flaw

def multi_step_checkout(cart_items, discount_code, user, payment_method):
    # Step 1: Validate cart items
    def validate_cart_items(items):
        if not items:
            raise ValueError("Cart is empty")
        for item in items:
            if item.get('quantity', 0) <= 0:
                raise ValueError("Invalid quantity in cart")
            if item.get('price', 0) < 0:
                raise ValueError("Invalid price in cart")
        return True
    
    # Step 2: Apply discount codes
    def apply_discount_code(code, items, user):
        valid_codes = {
            'SAVE10': {'discount': 0.1, 'admin_only': False, 'tier_required': None},
            'SAVE20': {'discount': 0.2, 'admin_only': False, 'tier_required': 'premium'},
            'SAVE30': {'discount': 0.3, 'admin_only': True, 'tier_required': None},
            'SAVE50': {'discount': 0.5, 'admin_only': False, 'tier_required': 'vip'}
        }
        
        if not code or code not in valid_codes:
            return {'discount': 0, 'code': None}
        
        discount_info = valid_codes[code]
        
        # Check admin only
        if discount_info['admin_only'] and not user.get('is_admin', False):
            raise ValueError("Admin only discount code")
        
        # Check user tier
        if discount_info['tier_required'] and user.get('tier') != discount_info['tier_required']:
            raise ValueError(f"Tier {discount_info['tier_required']} required for this discount")
        
        total = sum(item.get('price', 0) * item.get('quantity', 0) for item in items)
        discount_amount = total * discount_info['discount']
        
        return {'discount': discount_amount, 'code': code, 'discount_rate': discount_info['discount']}
    
    # Step 3: Calculate tax
    def calculate_tax(subtotal, discount_amount):
        tax_rate = 0.08
        taxable_amount = subtotal - discount_amount
        tax = taxable_amount * tax_rate
        return tax
    
    # Step 4: Process payment
    def process_payment(amount, payment_method, user):
        if not payment_method:
            raise ValueError("Payment method required")
        
        if user.get('balance', 0) < amount:
            raise ValueError("Insufficient balance")
        
        # Simulate payment processing
        return {'status': 'success', 'transaction_id': 'txn_' + str(hash(amount))}
    
    # Step 5: Create order record
    def create_order_record(items, discount_info, tax, payment_info, user):
        order = {
            'items': items,
            'subtotal': sum(item.get('price', 0) * item.get('quantity', 0) for item in items),
            'discount': discount_info['discount'],
            'tax': tax,
            'total': sum(item.get('price', 0) * item.get('quantity', 0) for item in items) - discount_info['discount'] + tax,
            'payment': payment_info,
            'user_id': user.get('id'),
            'discount_code': discount_info['code'],
            'order_date': '2023-01-01'
        }
        return order
    
    # Execute steps
    try:
        validate_cart_items(cart_items)
        
        subtotal = sum(item.get('price', 0) * item.get('quantity', 0) for item in cart_items)
        
        discount_info = apply_discount_code(discount_code, cart_items, user)
        
        tax = calculate_tax(subtotal, discount_info['discount'])
        
        total_amount = subtotal - discount_info['discount'] + tax
        
        payment_info = process_payment(total_amount, payment_method, user)
        
        order_record = create_order_record(cart_items, discount_info, tax, payment_info, user)
        
        return order_record
        
    except Exception as e:
        raise e

# Example usage:
